def summarize_downtime(events: list[dict[str, int]], grace_minutes: int) -> list[tuple[int, int, int]]:
    if grace_minutes < 0:
        raise ValueError('grace_minutes must be nonnegative')
    by_service: dict[int, list[tuple[int, int]]] = {}
    for event in events:
        service = event['service']
        start = event['start']
        end = event['end']
        if end < start:
            raise ValueError('event end before start')
        by_service.setdefault(service, []).append((start, end))
    merged: list[tuple[int, int, int]] = []
    for service in sorted(by_service):
        intervals = sorted(by_service[service])
        cur_start, cur_end = intervals[0]
        for start, end in intervals[1:]:
            if start - cur_end <= grace_minutes:
                cur_end = max(cur_end, end)
            else:
                merged.append((service, cur_start, cur_end))
                cur_start, cur_end = start, end
        merged.append((service, cur_start, cur_end))
    return merged
```

